Author: bruce <openclaw@claw.com>
Date:   Wed Jun 10 19:23:52 2026 +0800

    feat(v0.6.1-B): video history UI in renderer

    - index.html: add 📜 历史 button + collapsible list
    - app.js: videoHistory helper (refresh/add/remove/clear/checkExists)
    - app.js: auto-write history on video loadedmetadata (URL) and onchange (local)
    - app.js: click history item → reload video
    - app.js: missing file detection (electron-store checkExists) + gray out
    - style.css: history list + missing state styles
    - escapeHtml + formatTime helpers (XSS safe + friendly time)

    Unit test: 88/88 pass (no new tests in this task)
    Manual smoke: electron start → load video → history persists → reload

    Lesson: AGENT_PRACTICES #16 (--add-dir)

diff --git a/src/client/app.js b/src/client/app.js
index 8785b78..a6fe361 100644
--- a/src/client/app.js
+++ b/src/client/app.js
@@ -89,6 +89,142 @@
     }
   }

+  /** v0.6.1 FR-4: HTML 转义,防 XSS */
+  function escapeHtml(s) {
+    return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c]);
+  }
+
+  /** v0.6.1 FR-4: 友好时间显示 */
+  function formatTime(ts) {
+    const d = new Date(ts);
+    const now = Date.now();
+    const diff = (now - ts) / 1000;
+    if (diff < 60) return '刚刚';
+    if (diff < 3600) return `${Math.floor(diff/60)} 分钟前`;
+    if (diff < 86400) return `${Math.floor(diff/3600)} 小时前`;
+    if (diff < 86400*7) return `${Math.floor(diff/86400)} 天前`;
+    return d.toLocaleDateString('zh-CN');
+  }
+
+  // ============ v0.6.1 FR-4: 视频历史记录 ============
+  // 守卫: web 浏览器 (无 electron) 时静默跳过所有调用
+  const videoHistory = {
+    list: [],
+
+    async refresh() {
+      if (!window.desktopAPI?.videoHistory) return;
+      this.list = await window.desktopAPI.videoHistory.get();
+      this.render();
+    },
+
+    async addLocal(file) {
+      if (!window.desktopAPI?.videoHistory) return;
+      const path = window.desktopAPI.getPathForFile(file);
+      if (!path) return; // Electron < 30 不支持, 跳过
+      await window.desktopAPI.videoHistory.add({
+        type: 'local',
+        path: path,
+        name: file.name,
+        size: file.size,
+        mtime: file.lastModified,
+        addedAt: Date.now(),
+      });
+      await this.refresh();
+    },
+
+    async addUrl(url) {
+      if (!window.desktopAPI?.videoHistory) return;
+      const title = (url.split('/').pop() || '').split('?')[0] || url;
+      await window.desktopAPI.videoHistory.add({
+        type: 'url',
+        url: url,
+        title: title,
+        addedAt: Date.now(),
+      });
+      await this.refresh();
+    },
+
+    async remove(addedAt) {
+      if (!window.desktopAPI?.videoHistory) return;
+      await window.desktopAPI.videoHistory.remove(addedAt);
+      await this.refresh();
+    },
+
+    async clear() {
+      if (!confirm('确定清空所有视频历史? 此操作不可恢复。')) return;
+      if (!window.desktopAPI?.videoHistory) return;
+      await window.desktopAPI.videoHistory.clear();
+      await this.refresh();
+    },
+
+    async checkExists(path) {
+      if (!window.desktopAPI?.videoHistory) return false;
+      return await window.desktopAPI.videoHistory.checkExists(path);
+    },
+
+    render() {
+      const countEl = document.getElementById('videoHistoryCount');
+      const listEl = document.getElementById('videoHistoryList');
+      if (!countEl || !listEl) return;
+
+      countEl.textContent = this.list.length;
+
+      if (this.list.length === 0) {
+        listEl.innerHTML = '<div class="video-history-empty">暂无历史</div>';
+        return;
+      }
+
+      // 渲染列表
+      listEl.innerHTML = this.list.map(item => {
+        if (item.type === 'local') {
+          return `
+            <div class="video-history-item" data-added-at="${item.addedAt}">
+              <div class="video-history-icon">📁</div>
+              <div class="video-history-info">
+                <div class="video-history-name"...

