/**
 * v0.6.1-B Test Harness - Main Process
 *
 * v5: Refresh trigger via addUrl (synthetic file path injection doesn't work due to contextBridge)
 */

const { app, BrowserWindow, ipcMain, webUtils } = require('electron');
const path = require('path');
const fs = require('fs');
const Store = require('electron-store');

const TEST_USER_DATA = `/tmp/syncplay-v061b-test-${Date.now()}`;
app.setPath('userData', TEST_USER_DATA);
console.log(`[TEST-B-MAIN] userData set to: ${TEST_USER_DATA}`);

const TEST_RESULTS = {};
function recordResult(name, value) {
  const s = JSON.stringify(value);
  console.log(`[TEST-B-RESULT] ${name}: ${s.substring(0, 1500)}`);
  TEST_RESULTS[name] = value;
}

const videoHistoryStore = new Store({
  name: 'video-history',
  defaults: { items: [] },
});

ipcMain.handle('video-history:get', () => videoHistoryStore.get('items', []));
ipcMain.handle('video-history:add', (event, item) => {
  if (!item || !item.type) throw new Error('video-history:add: item.type is required');
  const items = videoHistoryStore.get('items', []);
  const dedupeKey = item.type === 'local' ? `local:${item.path}` : `url:${item.url}`;
  const filtered = items.filter(existing => {
    const existingKey = existing.type === 'local' ? `local:${existing.path}` : `url:${existing.url}`;
    return existingKey !== dedupeKey;
  });
  filtered.unshift(item);
  const truncated = filtered.slice(0, 20);
  videoHistoryStore.set('items', truncated);
  return truncated;
});
ipcMain.handle('video-history:remove', (event, addedAt) => {
  const items = videoHistoryStore.get('items', []);
  const filtered = items.filter(item => item.addedAt !== addedAt);
  videoHistoryStore.set('items', filtered);
  return filtered;
});
ipcMain.handle('video-history:clear', () => {
  videoHistoryStore.set('items', []);
  return [];

